            Self::Info    => "System notification",
        }
    }

    pub fn semantic_state(&self) -> &'static str {
        match self {
            Self::Error   => "open error",
            Self::Warning => "open warning",
            Self::Success => "open success",
            Self::Info    => "open info",
        }
    }
