}
impl ChartType {
    pub fn as_str(&self) -> &'static str {
        match self {
            Self::Bar     => "bar",
            Self::Line    => "line",
            Self::Area    => "area",
            Self::Pie     => "pie",
            Self::Donut   => "donut",
            Self::Scatter => "scatter",
            Self::Radar   => "radar",
        }
    }
}

#[component]
pub fn ChartPrimitive(
    #[prop(into, default = String::new())] class: String,
    #[prop(default = ChartType::Bar)] chart_type: ChartType,
