            class=class
        >
            <span data-rs-error-text="">{children()}</span>
        </div>
    }
}

#[component]
pub fn FormHintPrimitive(
    children: Children,
    #[prop(into, default = String::new())] class: String,
) -> impl IntoView {
    view! {
        <div data-rs-form-hint="" class=class>
            <span data-rs-form-hint-text="">{children()}</span>
        </div>
    }
}

