        match self {
            Self::Top    => "top",
            Self::Bottom => "bottom",
            Self::Left   => "left",
            Self::Right  => "right",
        }
    }
}


#[component]
pub fn HoverCardPrimitive(
    children: Children,
    #[prop(default = VisibilityState::Closed)] state: VisibilityState,
