    let pressed_state  = if pressed  { ToggleState::On }         else { ToggleState::Off };
    view! {
        <IconButtonUi
            aria_label=aria_label
            variant=variant
            size=size
            disabled=disabled_state
            loading=loading_state
            pressed=pressed_state
            class=class
        >
            {children()}
        </IconButtonUi>
    }
}

