            data-rs-disabled=d.data_rs_disabled
            aria-disabled=d.aria_disabled
            aria-label="Go to next page"
            href=if d.disabled { "#".to_string() } else { href }
            tabindex=if d.disabled { "-1" } else { "0" }
            class=class
        >
            {children()}
        </a>
    }
}

